class Solution {
public:
    int minimumOperationsToMakeEqual(int x, int y) {
        int diff = abs(x - y);
        int ops = 0;
        while (diff > 0) {
            if (diff % 11 == 0) diff /= 11;
            else if (diff % 5 == 0) diff /= 5;
            else diff--;
            ops++;
        }
        return ops;
    }
};
